import React, { useState, useEffect } from "react";
import { adminAPI } from "../services/api";

const AdminDashboard = () => {
  const [events, setEvents] = useState([]);
  const [staff, setStaff] = useState([]);
  const [showCreateEvent, setShowCreateEvent] = useState(false);
  const [showCreateStaff, setShowCreateStaff] = useState(false);

  const [eventForm, setEventForm] = useState({
    title: "",
    description: "",
    date: "",
    time: "",
    venue: "",
    maxParticipants: "",
    category: "",
    allowedDepartments: [],
    allowedClasses: [],
  });

  const [staffForm, setStaffForm] = useState({
    name: "",
    email: "",
    password: "",
    staffId: "",
    staffDepartment: "",
    className: "",
    phone: "",
  });

  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [eventsRes, staffRes] = await Promise.all([
        adminAPI.getAllEvents(),
        adminAPI.getAllStaff(),
      ]);
      setEvents(eventsRes.data);
      setStaff(staffRes.data);
    } catch {
      setError("Failed to load data");
    } finally {
      setLoading(false);
    }
  };

  const handleEventSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setSuccess("");

    try {
      await adminAPI.createEvent({
        ...eventForm,
        allowedDepartments: eventForm.allowedDepartments.filter(Boolean),
        allowedClasses: eventForm.allowedClasses.filter(Boolean),
      });
      setSuccess("Event created successfully!");
      setShowCreateEvent(false);
      setEventForm({
        title: "",
        description: "",
        date: "",
        time: "",
        venue: "",
        maxParticipants: "",
        category: "",
        allowedDepartments: [],
        allowedClasses: [],
      });
      fetchData();
    } catch (err) {
      setError(err.response?.data?.message || "Failed to create event");
    }
  };

  const handleStaffSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setSuccess("");

    try {
      await adminAPI.createStaff(staffForm);
      setSuccess("Staff created successfully!");
      setShowCreateStaff(false);
      setStaffForm({
        name: "",
        email: "",
        password: "",
        staffId: "",
        staffDepartment: "",
        className: "",
        phone: "",
      });
      fetchData();
    } catch (err) {
      setError(err.response?.data?.message || "Failed to create staff");
    }
  };

  if (loading) {
    return <p className="text-center text-gray-600">Loading...</p>;
  }

  return (
    <div className="space-y-8">
      <h2 className="text-2xl font-semibold text-gray-900">
        Admin Dashboard
      </h2>

      {error && (
        <div className="rounded-md bg-red-100 px-4 py-2 text-red-700">
          {error}
        </div>
      )}
      {success && (
        <div className="rounded-md bg-green-100 px-4 py-2 text-green-700">
          {success}
        </div>
      )}

      {/* ACTION BUTTONS */}
      <div className="flex gap-4">
        <button
          onClick={() => {
            setShowCreateEvent(true);
            setShowCreateStaff(false);
          }}
          className="rounded-md bg-indigo-600 px-4 py-2 text-white hover:bg-indigo-700"
        >
          Create Event
        </button>

        <button
          onClick={() => {
            setShowCreateStaff(true);
            setShowCreateEvent(false);
          }}
          className="rounded-md bg-green-600 px-4 py-2 text-white hover:bg-green-700"
        >
          Create Staff Account
        </button>
      </div>

      {/* CREATE EVENT */}
      {showCreateEvent && (
        <div className="rounded-lg bg-white p-6 shadow space-y-4">
          <h3 className="text-lg font-semibold">Create New Event</h3>

          <form onSubmit={handleEventSubmit} className="space-y-4">
            <input
              className="input"
              placeholder="Title"
              value={eventForm.title}
              onChange={(e) =>
                setEventForm({ ...eventForm, title: e.target.value })
              }
              required
            />

            <textarea
              className="input"
              placeholder="Description"
              value={eventForm.description}
              onChange={(e) =>
                setEventForm({ ...eventForm, description: e.target.value })
              }
              required
            />

            <div className="grid grid-cols-2 gap-4">
              <input
                type="date"
                className="input"
                value={eventForm.date}
                onChange={(e) =>
                  setEventForm({ ...eventForm, date: e.target.value })
                }
                required
              />
              <input
                type="time"
                className="input"
                value={eventForm.time}
                onChange={(e) =>
                  setEventForm({ ...eventForm, time: e.target.value })
                }
                required
              />
            </div>

            <input
              className="input"
              placeholder="Venue"
              value={eventForm.venue}
              onChange={(e) =>
                setEventForm({ ...eventForm, venue: e.target.value })
              }
              required
            />

            <div className="grid grid-cols-2 gap-4">
              <input
                type="number"
                className="input"
                placeholder="Max Participants"
                value={eventForm.maxParticipants}
                onChange={(e) =>
                  setEventForm({
                    ...eventForm,
                    maxParticipants: e.target.value,
                  })
                }
                required
              />
              <input
                className="input"
                placeholder="Category"
                value={eventForm.category}
                onChange={(e) =>
                  setEventForm({ ...eventForm, category: e.target.value })
                }
                required
              />
            </div>

            <input
              className="input"
              placeholder="Allowed Departments (CSE, ECE)"
              value={eventForm.allowedDepartments.join(", ")}
              onChange={(e) =>
                setEventForm({
                  ...eventForm,
                  allowedDepartments: e.target.value
                    .split(",")
                    .map((d) => d.trim()),
                })
              }
            />

            <input
              className="input"
              placeholder="Allowed Classes (CSE-2A)"
              value={eventForm.allowedClasses.join(", ")}
              onChange={(e) =>
                setEventForm({
                  ...eventForm,
                  allowedClasses: e.target.value
                    .split(",")
                    .map((c) => c.trim()),
                })
              }
            />

            <div className="flex gap-4">
              <button className="btn-primary">Create Event</button>
              <button
                type="button"
                onClick={() => setShowCreateEvent(false)}
                className="btn-secondary"
              >
                Cancel
              </button>
            </div>
          </form>
        </div>
      )}

      {/* LISTS */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div>
          <h3 className="mb-4 text-lg font-semibold">
            Events ({events.length})
          </h3>
          <div className="space-y-3">
            {events.map((event) => (
              <div
                key={event._id}
                className="rounded-md bg-white p-4 shadow"
              >
                <h4 className="font-semibold">{event.title}</h4>
                <p className="text-sm text-gray-600">
                  Date: {new Date(event.date).toLocaleDateString()}
                </p>
                <p className="text-sm text-gray-600">
                  Venue: {event.venue}
                </p>
              </div>
            ))}
          </div>
        </div>

        <div>
          <h3 className="mb-4 text-lg font-semibold">
            Staff Accounts ({staff.length})
          </h3>
          <div className="space-y-3">
            {staff.map((s) => (
              <div
                key={s._id}
                className="rounded-md bg-white p-4 shadow"
              >
                <h4 className="font-semibold">{s.name}</h4>
                <p className="text-sm text-gray-600">{s.email}</p>
                <p className="text-sm text-gray-600">
                  {s.staffDepartment} — {s.className}
                </p>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminDashboard;
